     1→import { useCallback, useEffect, useRef, useState } from 'react';
     2→
     3→const SLASH_COMMANDS = [
     4→  { cmd: '/chart', aliases: ['/시각화'], desc: '차트 생성', icon: '📊', action: { type: 'param', key: 'use_visualization', value: true, prefix: '[시각화 요청] ' } },
     5→  { cmd: '/search', aliases: ['/검색'], desc: '웹 검색', icon: '🔍', action: { type: 'param', key: 'use_web_search', value: true } },
     6→  { cmd: '/compare', aliases: ['/비교'], desc: '종목 비교', icon: '⚖️', action: { type: 'param', key: 'response_mode', value: 'comparison' } },
     7→  { cmd: '/quiz', aliases: ['/퀴즈'], desc: '퀴즈 시작', icon: '❓', action: { type: 'navigate', path: '/education', tab: 'quiz' } },
     8→  { cmd: '/portfolio', aliases: ['/포트폴리오'], desc: '내 자산', icon: '💼', action: { type: 'action', actionId: 'nav_portfolio' } },
     9→  { cmd: '/buy', aliases: ['/매수'], desc: '매수', icon: '📈', action: { type: 'action', actionId: 'buy_stock' } },
    10→];
    11→
    12→export { SLASH_COMMANDS };
    13→
    14→/**
    15→ * SlashCommandMenu - "/" 입력 시 나타나는 슬래시 커맨드 팝업 메뉴
    16→ *
    17→ * @param {string} query - "/" 뒤에 입력된 텍스트 (예: 사용자가 "/ch" 입력 → query = "ch")
    18→ * @param {function} onSelect - 커맨드 선택 시 호출 (command 객체 전달)
    19→ * @param {function} onClose - 메뉴 닫기 시 호출
    20→ * @param {boolean} visible - 메뉴 표시 여부
    21→ */
    22→export default function SlashCommandMenu({ query, onSelect, onClose, visible }) {
    23→  const [activeIndex, setActiveIndex] = useState(0);
    24→  const menuRef = useRef(null);
    25→
    26→  // query로 커맨드 필터링 (cmd, aliases 모두 매칭)
    27→  const filtered = SLASH_COMMANDS.filter((command) => {
    28→    const q = (query || '').toLowerCase();
    29→    if (!q) return true;
    30→    const cmdMatch = command.cmd.slice(1).toLowerCase().startsWith(q);
    31→    const aliasMatch = command.aliases.some((alias) => alias.slice(1).toLowerCase().startsWith(q));
    32→    const descMatch = command.desc.toLowerCase().includes(q);
    33→    return cmdMatch || aliasMatch || descMatch;
    34→  });
