    41→  // 키보드 네비게이션 핸들러
    42→  const handleKeyDown = useCallback((e) => {
    43→    if (!visible || filtered.length === 0) return;
    44→
    45→    if (e.key === 'ArrowDown') {
    46→      e.preventDefault();
    47→      setActiveIndex((prev) => (prev + 1) % filtered.length);
    48→    } else if (e.key === 'ArrowUp') {
    49→      e.preventDefault();
    50→      setActiveIndex((prev) => (prev - 1 + filtered.length) % filtered.length);
    51→    } else if (e.key === 'Enter') {
    52→      e.preventDefault();
    53→      onSelect(filtered[activeIndex]);
    54→    } else if (e.key === 'Escape') {
    55→      e.preventDefault();
    56→      onClose();
    57→    }
    58→  }, [visible, filtered, activeIndex, onSelect, onClose]);
