    61→  useEffect(() => {
    62→    if (!visible) return undefined;
    63→    window.addEventListener('keydown', handleKeyDown);
    64→    return () => window.removeEventListener('keydown', handleKeyDown);
    65→  }, [visible, handleKeyDown]);
    66→
    67→  // 활성 아이템 스크롤 보장
    68→  useEffect(() => {
    69→    if (!menuRef.current) return;
    70→    const activeEl = menuRef.current.querySelector('[data-active="true"]');
    71→    if (activeEl) {
    72→      activeEl.scrollIntoView({ block: 'nearest' });
    73→    }
    74→  }, [activeIndex]);
    75→
    76→  if (!visible || filtered.length === 0) return null;
    77→
    78→  return (
    79→    <div
    80→      ref={menuRef}
    81→      className="absolute bottom-full left-0 right-0 z-50 mb-2 overflow-hidden rounded-xl bg-white shadow-lg ring-1 ring-black/5"
    82→      role="listbox"
    83→      aria-label="슬래시 커맨드 목록"
