    85→      <div className="max-h-[240px] overflow-y-auto py-1">
    86→        {filtered.slice(0, 5).map((command, index) => {
    87→          const isActive = index === activeIndex;
    88→          return (
    89→            <button
    90→              key={command.cmd}
    91→              type="button"
    92→              role="option"
    93→              aria-selected={isActive}
    94→              data-active={isActive}
    95→              onClick={() => onSelect(command)}
