    17→import { normalizeTraces } from '../../utils/plotly/normalizeTraces';
    18→import { trackEvent, TRACK_EVENTS } from '../../utils/analytics';
    19→
    20→// 출처 분류 체계
    21→const SOURCE_LABELS = {
    22→  glossary:    { icon: '\uD83D\uDCD6', label: '자체 용어집',    desc: '투자 용어 사전 (DB)' },
    23→  case:        { icon: '\uD83D\uDCCB', label: '역사적 사례',    desc: 'DB 저장 과거 사례 분석' },
    24→  report:      { icon: '\uD83D\uDCC4', label: '증권사 리포트',  desc: '네이버 금융 크롤링' },
    25→  dart:        { icon: '\uD83C\uDFDB\uFE0F', label: 'DART 공시', desc: '금융감독원 전자공시' },
    26→  news:        { icon: '\uD83D\uDCF0', label: '뉴스 기사',      desc: '언론 보도 링크' },
    27→  stock_price: { icon: '\uD83D\uDCC8', label: '실시간 시세',    desc: 'pykrx 주가 조회' },
    28→  financial:   { icon: '\uD83D\uDCB9', label: '재무제표',       desc: 'FinanceDataReader' },
    29→  web:         { icon: '\uD83C\uDF10', label: '웹 검색',        desc: 'Perplexity 검색' },
    30→};
    31→
    32→function normalizeMathDelimiters(content) {
    33→  if (!content) return '';
    34→
    35→  let normalized = String(content).replace(/\r\n/g, '\n');
    36→
    37→  // MathJax 스타일 블록 수식(\[...\])을 KaTeX 호환 블록($$...$$)으로 정규화
    38→  normalized = normalized.replace(
    39→    /(?:^|\n)\s*\\\[\s*([\s\S]*?)\s*\\?\]\s*(?=\n|$)/g,
    40→    (_, expr) => `\n$$\n${expr.trim()}\n$$\n`,
    41→  );
    42→
    43→  // MathJax 스타일 인라인 수식(\(...\))을 KaTeX 호환 인라인($...$)으로 정규화
    44→  normalized = normalized.replace(/\\\(\s*([\s\S]*?)\s*\\\)/g, (_, expr) => `$${expr.trim()}$`);
    45→
    46→  return normalized;
    47→}
    48→
    49→function SourceBadge({ sources }) {
    50→  const [open, setOpen] = useState(false);
    51→  return (
