    55→        <span className="font-medium">{sources.length}개 출처</span>
    56→        <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" style={{ transform: open ? 'rotate(180deg)' : 'rotate(0)', transition: 'transform 0.2s' }}><path d="M6 9l6 6 6-6" /></svg>
    57→      </button>
    58→      {open && (
    59→        <div className="mt-2 space-y-2 pl-0.5">
    60→          {sources.map((s, i) => {
    61→            const meta = SOURCE_LABELS[s.type] || SOURCE_LABELS.web;
    62→            const hasUrl = s.url && (s.url.startsWith('http') || s.url.startsWith('/'));
    63→            const isExternal = s.url && s.url.startsWith('http');
