    72→                        href={s.url}
    73→                        target={isExternal ? '_blank' : '_self'}
    74→                        rel={isExternal ? 'noopener noreferrer' : undefined}
    75→                        className="text-primary hover:underline font-medium"
    76→                        onClick={() => trackEvent('tutor_source_click', { source_type: s.type, url: s.url })}
    77→                      >
    78→                        {s.title}
    79→                        {isExternal && <span className="ml-0.5 text-[9px] opacity-50">\u2197</span>}
    80→                      </a>
    81→                    ) : (
    82→                      <span className="font-medium text-text-primary">{s.title}</span>
    83→                    )}
    84→                    {s.content && <span className="text-text-secondary ml-1">— {s.content.slice(0, 60)}</span>}
    85→                  </div>
