    96→/**
    97→ * 레거시 HTML에서 Plotly data/layout 추출 (하위 호환용)
    98→ * Plotly.newPlot('id', data, layout) 또는 var data/layout 패턴 매칭
    99→ */
   100→function extractPlotlyDataFromHtml(html) {
   101→  try {
   102→    // 패턴 1: Plotly.newPlot('id', [...], {...})
   103→    const plotCallMatch = html.match(
   104→      /Plotly\.(?:newPlot|react)\s*\(\s*['"][^'"]*['"]\s*,\s*([\s\S]+?)\s*,\s*(\{[\s\S]+?\})\s*[,)]/
   105→    );
   106→    if (plotCallMatch) {
   107→      // eslint-disable-next-line no-new-func
   108→      const data = new Function(`return ${plotCallMatch[1]}`)();
   109→      // eslint-disable-next-line no-new-func
   110→      const layout = new Function(`return ${plotCallMatch[2]}`)();
   111→      if (Array.isArray(data)) return { data, layout: layout || {} };
   112→    }
   113→    // 패턴 2: var data = [...]; var layout = {...};
   114→    const dataMatch = html.match(/(?:var|let|const)\s+data\s*=\s*([\s\S]+?);\s*(?:var|let|const)\s+layout/);
   115→    const layoutMatch = html.match(/(?:var|let|const)\s+layout\s*=\s*([\s\S]+?);\s*(?:Plotly|<\/script)/);
   116→    if (dataMatch && layoutMatch) {
   117→      // eslint-disable-next-line no-new-func
   118→      const data = new Function(`return ${dataMatch[1].trim()}`)();
   119→      // eslint-disable-next-line no-new-func
   120→      const layout = new Function(`return ${layoutMatch[1].trim()}`)();
   121→      if (Array.isArray(data)) return { data, layout: layout || {} };
   122→    }
   123→  } catch (e) {
   124→    console.warn('Plotly HTML 파싱 실패:', e);
   125→  }
   126→  return null;
   127→}
   128→
   129→function VisualizationMessage({ message }) {
   130→  const [expanded, setExpanded] = useState(false);
   131→
   132→  // 차트 데이터 결정: JSON(chartData) 우선 → 레거시 HTML 폴백
   133→  let chartData = null;
   134→  if (message.chartData && message.chartData.data) {
   135→    chartData = message.chartData;
   136→  } else if (message.format === 'html' && message.content) {
   137→    chartData = extractPlotlyDataFromHtml(message.content);
   138→  }
   139→
   140→  const normalizedData = normalizeTraces(chartData?.data);
   141→  const hasChart = normalizedData.length > 0;
   142→  const hasPie = normalizedData.some((trace) => trace.type === 'pie');
   143→  const normalizedLayout = normalizeLayout(chartData?.layout || {}, { hasPie, clearTitle: false });
   144→  const fixedHeight = expanded ? 440 : 280;
   145→
   146→  return (
   147→    <motion.div className="mb-4" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}>
   148→      <div className="flex items-center gap-1.5 mb-1.5">
   149→        <img src="/images/penguin-3d.png" alt="" className="w-5 h-5 rounded-full object-cover" />
   150→        <span className="text-xs text-text-secondary">차트</span>
   151→        {message.executionTime && <span className="text-[10px] text-text-secondary ml-auto">{message.executionTime}ms</span>}
   152→      </div>
   153→      <div className="max-w-[480px] overflow-hidden rounded-2xl border border-border bg-white p-2 transition-all">
   154→        {hasChart ? (
   155→          <ResponsivePlotly
   156→            data={normalizedData}
   157→            layout={normalizedLayout}
   158→            mode="fixed"
   159→            fixedHeight={fixedHeight}
   160→            minHeight={fixedHeight}
   161→            maxHeight={fixedHeight}
   162→            loadingText="차트 로딩 중..."
   163→            emptyText="차트를 생성할 수 없습니다"
   164→          />
   165→        ) : (
   166→          <div className="flex items-center justify-center text-sm text-text-secondary" style={{ height: fixedHeight }}>
   167→            차트를 생성할 수 없습니다
   168→          </div>
   169→        )}
   170→      </div>
   171→      {hasChart && (
   172→        <button onClick={() => setExpanded(!expanded)} className="text-xs text-text-secondary hover:text-primary transition-colors mt-1">
   173→          {expanded ? '축소' : '확대'}
   174→        </button>
   175→      )}
   176→    </motion.div>
   177→  );
   178→}
   179→
   180→export function TypingIndicator() {
   181→  return (
   182→    <motion.div className="flex justify-start mb-3" initial={{opacity:0,y:10}} animate={{opacity:1,y:0}}>
   183→      <div className="bg-surface px-3 py-2 rounded-2xl rounded-bl-md">
   184→        <PenguinLoading message="분석 중이에요..." />
   185→      </div>
   186→    </motion.div>
   187→  );
   188→}
   189→
   190→export default React.memo(function Message({ message, onActionClick }) {
   191→  const markdownContent = useMemo(
   192→    () => normalizeMathDelimiters(message.content),
   193→    [message.content],
   194→  );
   195→  if (message.role === 'visualization') return <VisualizationMessage message={message} />;
   196→
   197→  const isUser = message.role === 'user';
   198→
   199→  if (isUser) {
   200→    return (
   201→      <motion.div className="flex justify-end mb-3" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}>
   202→        <div className="max-w-[85%] px-4 py-2.5 rounded-2xl bg-primary text-white rounded-br-md">
   203→          <p className="text-sm">{message.content}</p>
   204→        </div>
   205→      </motion.div>
   206→    );
   207→  }
   208→
   209→  return (
   210→    <motion.div className="flex justify-start mb-4" initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}>
   211→      <div className="max-w-[90%]">
   212→        <div className="flex items-center gap-1.5 mb-1.5">
   213→          <img src="/images/penguin-3d.png" alt="" className="w-5 h-5 rounded-full object-cover" />
   214→          <span className="text-xs text-text-secondary font-medium">AI 튜터</span>
   215→        </div>
   216→        <div className={`px-4 py-3 rounded-2xl rounded-tl-md ${message.isError ? 'bg-error-light text-error border border-error/20' : 'bg-surface border border-border'}`}>
   217→          {message.isError ? <p className="text-sm">{message.content}</p> : (
   218→            <div className="text-sm leading-relaxed text-text-primary prose prose-sm prose-headings:text-text-primary prose-strong:text-text-primary prose-code:text-primary prose-code:bg-gray-100 prose-code:px-1 prose-code:py-0.5 prose-code:rounded prose-code:text-xs max-w-none dark:prose-invert">
   219→              <ReactMarkdown remarkPlugins={[remarkMath, remarkGfm, remarkBreaks]} rehypePlugins={[rehypeRaw, rehypeKatex]}>
   220→                {markdownContent}
   221→              </ReactMarkdown>
   222→            </div>
   223→          )}
   224→          {message.isStreaming && <span className="inline-block w-1.5 h-4 bg-primary animate-pulse ml-0.5 rounded-sm" />}
   225→        </div>
   226→        {message.sources && message.sources.length > 0 && <SourceBadge sources={message.sources} />}
   227→        {!message.isStreaming && message.id && (
   228→          <div className="mt-1">
   229→            <ReactionButtons contentType="tutor_message" contentId={message.id} />
   230→          </div>
   231→        )}
   232→        {/* 후속 액션 버튼 */}
   233→        {!message.isStreaming && message.actions && message.actions.length > 0 && (
   234→          <div className="mt-2 flex flex-wrap gap-1.5">
   235→            {message.actions.map((action, idx) => (
   236→              <button
   237→                key={idx}
   238→                onClick={() => {
   239→                  trackEvent(TRACK_EVENTS.ACTION_BUTTON_CLICK, { action_id: action.id, action_type: action.type });
   240→                  onActionClick?.(action);
   241→                }}
   242→                className={`rounded-lg px-3 py-1.5 text-[12px] font-medium transition-colors active:opacity-80 ${
   243→                  action.type === 'tool' && action.risk === 'high'
   244→                    ? 'bg-[#FFF2E8] text-[#FF6B00] border border-[#FF6B00]/20'
   245→                    : action.type === 'prompt'
   246→                    ? 'bg-[#F2F4F6] text-[#4E5968]'
   247→                    : 'bg-[#EBF5FF] text-[#1D6FDE]'
   248→                }`}
   249→              >
   250→                {action.label}
   251→              </button>
   252→            ))}
   253→          </div>
   254→        )}
   255→      </div>
   256→    </motion.div>
   257→  );
   258→})
