     1→/**
     2→ * TutorModal - AI 튜터 모달 레이아웃
     3→ *
     4→ * 메시지, 세션, 입력 UI는 각각 서브 컴포넌트로 분리됨.
     5→ */
     6→import { useState, useRef, useEffect, useCallback } from 'react';
     7→import { useNavigate } from 'react-router-dom';
     8→import { motion, AnimatePresence } from 'framer-motion';
     9→import { useTutor, useUser } from '../../contexts';
    10→import PenguinMascot from '../common/PenguinMascot';
    11→import Message, { TypingIndicator } from './MessageBubble';
    12→import SessionSidebar from './SessionSidebar';
    13→import ChatInput from './ChatInput';
    14→import { trackEvent, TRACK_EVENTS } from '../../utils/analytics';
    15→
    16→export default function TutorModal() {
    17→  const {
    18→    isOpen, closeTutor, messages, isLoading, sendMessage,
    19→    currentTerm, sessions, activeSessionId, contextInfo, agentStatus,
    20→    createNewChat, deleteChat, loadChatHistory, refreshSessions,
    21→  } = useTutor();
    22→  const { settings } = useUser();
    23→  const navigate = useNavigate();
    24→  const [input, setInput] = useState('');
    25→  const [isSessionsOpen, setIsSessionsOpen] = useState(false);
    26→  const messagesEndRef = useRef(null);
    27→  const inputRef = useRef(null);
    28→  const termSentRef = useRef(null);
    29→
    30→  useEffect(() => { messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages]);
    31→  useEffect(() => {
    32→    if (isOpen) {
    33→      refreshSessions();
    34→      setTimeout(() => inputRef.current?.focus(), 100);
    35→    } else {
    36→      setIsSessionsOpen(false);
    37→    }
    38→  }, [isOpen, refreshSessions]);
    39→  useEffect(() => {
    40→    if (isOpen && currentTerm && currentTerm !== termSentRef.current && !isLoading) {
    41→      termSentRef.current = currentTerm;
    42→      sendMessage(`'${currentTerm}'에 대해 설명해주세요.`, settings.difficulty);
    43→    }
    44→  }, [isOpen, currentTerm, isLoading, sendMessage, settings.difficulty]);
    45→
    46→  const handleSubmit = (e) => {
    47→    e.preventDefault();
    48→    if (!input.trim() || isLoading) return;
    49→    sendMessage(input.trim(), settings.difficulty);
    50→    setInput('');
    51→  };
    52→
    53→  const handleNewChat = async () => {
    54→    try { await createNewChat(); setIsSessionsOpen(false); } catch (e) { console.error('새 대화 생성 실패:', e); }
    55→  };
    56→  const handleSessionClick = async (id) => {
    57→    try { await loadChatHistory(id); setIsSessionsOpen(false); } catch (e) { console.error('대화 로드 실패:', e); }
    58→  };
    59→  const handleDeleteSession = async (id) => {
    60→    if (window.confirm('이 대화를 삭제하시겠습니까?')) {
    61→      try { await deleteChat(id); } catch (e) { console.error('삭제 실패:', e); }
    62→    }
    63→  };
    64→
    65→  const handleActionClick = useCallback((action) => {
    66→    if (action.type === 'prompt') {
    67→      // 추천 질문을 입력에 세팅 후 자동 전송
    68→      setInput(action.label);
    69→      setTimeout(() => {
    70→        handleSubmit({ preventDefault: () => {} });
    71→      }, 100);
    72→    } else if (action.type === 'navigate') {
    73→      // 지정된 페이지로 이동
    74→      navigate(action.params?.path || '/home');
    75→    } else if (action.type === 'tool') {
    76→      // 도구 액션은 프롬프트로 변환하여 입력
    77→      setInput(`${action.label} 실행해줘`);
    78→    }
    79→  }, [navigate, handleSubmit]);
    80→
    81→  return (
    82→    <AnimatePresence>
    83→      {isOpen && (
    84→        <>
    85→          <motion.div className="fixed inset-0 bg-black/50 z-40" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={closeTutor} />
    86→          <motion.div
    87→            className="fixed inset-x-0 bottom-0 bg-background rounded-t-3xl z-50 max-w-mobile mx-auto flex flex-col"
    88→            style={{ height: '85vh' }}
    89→            initial={{ y: '100%' }} animate={{ y: 0 }} exit={{ y: '100%' }}
    90→            transition={{ type: 'spring', damping: 25, stiffness: 300 }}
    91→          >
    92→            {/* Header */}
    93→            <div className="border-b border-border">
    94→              <div className="flex items-center justify-between p-4">
    95→                <div className="flex items-center gap-2">
    96→                  <img src="/images/penguin-3d.png" alt="AI Tutor" className="w-8 h-8" />
    97→                  <div>
    98→                    <h2 className="font-bold text-text-primary">AI 튜터</h2>
    99→                    <p className="text-xs text-text-secondary capitalize">{settings.difficulty} 모드</p>
   100→                  </div>
   101→                </div>
   102→                <div className="flex items-center gap-2">
   103→                  <button onClick={handleNewChat} className="px-3 py-1.5 text-sm bg-primary text-white rounded-lg hover:bg-primary-hover transition-colors">새 대화</button>
   104→                  <button onClick={() => setIsSessionsOpen((prev) => !prev)} className="px-3 py-1.5 text-sm bg-surface text-text-primary border border-border rounded-lg hover:bg-surface-elevated transition-colors">대화 목록</button>
   105→                  <button onClick={closeTutor} className="p-2 rounded-lg hover:bg-surface transition-colors text-text-secondary">✕</button>
   106→                </div>
   107→              </div>
   108→              <div className="border-t border-border bg-surface px-4 py-2">
   109→                <p className="text-[11px] text-text-secondary">
   110→                  현재 보고 있는 화면: {contextInfo?.stepTitle || '일반 질문 모드'}
   111→                </p>
   112→                <p className="mt-1 text-[11px] text-text-secondary">
   113→                  AI 상태: {agentStatus?.text || '응답 대기 중'}
   114→                </p>
   115→              </div>
   116→              <SessionSidebar
   117→                sessions={sessions} activeSessionId={activeSessionId}
   118→                isOpen={isSessionsOpen}
   119→                onSessionClick={handleSessionClick} onDeleteSession={handleDeleteSession}
   120→              />
   121→            </div>
   122→
   123→            {/* Messages */}
   124→            <div className="flex-1 overflow-y-auto p-4">
   125→              {messages.length === 0 ? (
   126→                <div className="py-6 space-y-4">
   127→                  <div className="text-center">
   128→                    <PenguinMascot variant="welcome" message="안녕하세요! 시장에 대해 궁금한 점을 물어보세요." />
   129→                  </div>
   130→                </div>
   131→              ) : (
   132→                <>
   133→                  {messages.map((m) => <Message key={m.id} message={m} onActionClick={handleActionClick} />)}
   134→                  {isLoading && messages.length > 0 && messages[messages.length - 1]?.role === 'user' && <TypingIndicator />}
   135→                  <div ref={messagesEndRef} />
   136→                </>
   137→              )}
   138→            </div>
   139→
   140→            {/* Input */}
   141→            <ChatInput ref={inputRef} value={input} onChange={setInput} onSubmit={handleSubmit} isLoading={isLoading} />
   142→          </motion.div>
   143→        </>
   144→      )}
   145→    </AnimatePresence>
   146→  );
   147→}
