    67→  }, [searchEnabled]);
    68→
    69→  useEffect(() => {
    70→    try {
    71→      const hasStoredValue = localStorage.getItem(SEARCH_TOGGLE_KEY);
    72→      if (hasStoredValue === null) {
    73→        setSearchEnabled(mode === 'stock');
    74→      }
    75→    } catch {
    76→      setSearchEnabled(mode === 'stock');
    77→    }
    78→  }, [mode]);
    79→
    80→  useEffect(() => {
    81→    document.documentElement.style.setProperty('--keyboard-offset', `${keyboardOffset}px`);
    82→    return () => {
    83→      document.documentElement.style.setProperty('--keyboard-offset', '0px');
    84→    };
    85→  }, [keyboardOffset]);
    86→
    87→  const baseContextPayload = useMemo(() => {
    88→    if (mode === 'stock' && location.state?.stockContext) {
    89→      return location.state.stockContext;
    90→    }
    91→
    92→    if (mode === 'home') {
    93→      return readSessionJson('adelie_home_context');
    94→    }
    95→
    96→    if (mode === 'education') {
    97→      return readSessionJson('adelie_education_context');
    98→    }
    99→
   100→    return null;
   101→  }, [location.state, mode]);
   102→
   103→  const {
   104→    controlState,
   105→    isAgentControlling,
   106→    actionCatalog: orchestratorActionCatalog,
   107→    executeAction,
   108→  } = useAgentControlOrchestrator({
   109→    mode,
   110→    stockContext: baseContextPayload,
   111→  });
   112→
   113→  const actionCatalog = useMemo(
   114→    () => buildActionCatalog({ pathname: location.pathname, mode, stockContext: baseContextPayload }),
   115→    [baseContextPayload, location.pathname, mode],
   116→  );
   117→
   118→  const buildControlContextPayload = useCallback((prompt = '') => {
   119→    const uiSnapshot = buildUiSnapshot({
   120→      pathname: location.pathname,
   121→      mode,
   122→      locationState: location.state || null,
   123→      visibleSections: getVisibleSectionsByMode(mode),
   124→      selectedEntities: {
   125→        stock_code: baseContextPayload?.stock_code || null,
   126→        stock_name: baseContextPayload?.stock_name || null,
   127→        date_key: baseContextPayload?.date || null,
   128→        case_id: baseContextPayload?.case_id || null,
   129→      },
   130→      filters: {
   131→        tab: location.pathname.startsWith('/portfolio') ? 'portfolio' : mode,
   132→      },
   133→      portfolioSummary: baseContextPayload?.portfolio_summary || null,
   134→    });
   135→
   136→    return {
   137→      ...(baseContextPayload || {}),
   138→      ui_snapshot: uiSnapshot,
   139→      action_catalog: actionCatalog,
   140→      interaction_state: {
   141→        source: 'agent_dock',
   142→        mode,
   143→        route: location.pathname,
   144→        last_prompt: prompt || null,
   145→        search_enabled: searchEnabled,
   146→        control_phase: controlState.phase,
   147→        control_active: isAgentControlling,
   148→      },
   149→    };
   150→  }, [actionCatalog, baseContextPayload, controlState.phase, isAgentControlling, location.pathname, location.state, mode, searchEnabled]);
   151→
   152→  const handleSlashCommand = useCallback((command) => {
   153→    setShowSlashMenu(false);
   154→    setSlashQuery('');
   155→
   156→    const action = command.action;
   157→    if (action.type === 'navigate') {
   158→      navigate(action.path);
   159→    } else if (action.type === 'action') {
   160→      const matchedAction = orchestratorActionCatalog.find((item) => item.id === action.actionId);
   161→      if (matchedAction) {
   162→        executeAction(matchedAction, { contextPayload: buildControlContextPayload('') });
   163→      }
   164→    } else if (action.type === 'param') {
   165→      setInput(action.prefix || '');
   166→      if (action.key === 'use_web_search') {
   167→        setSearchEnabled(true);
   168→      }
   169→    }
   170→  }, [navigate, orchestratorActionCatalog, executeAction, buildControlContextPayload]);
   171→
   172→  const submitPromptToCanvas = useCallback((prompt) => {
   173→    const payload = buildControlContextPayload(prompt);
   174→
   175→    navigate('/agent', {
   176→      state: {
   177→        mode,
   178→        initialPrompt: prompt.trim(),
   179→        contextPayload: payload,
   180→        useWebSearch: searchEnabled,
   181→        resetConversation: location.pathname !== '/agent',
   182→      },
   183→    });
   184→  }, [buildControlContextPayload, location.pathname, mode, navigate, searchEnabled]);
   185→
   186→  const routePrompt = useCallback(async (prompt, payload) => {
   187→    const response = await authFetch(`${API_BASE_URL}/api/v1/tutor/route`, {
   188→      method: 'POST',
   189→      headers: { 'Content-Type': 'application/json' },
   190→      body: JSON.stringify({
   191→        message: prompt,
   192→        mode,
   193→        context_text: JSON.stringify(payload),
   194→        ui_snapshot: payload.ui_snapshot || null,
   195→        action_catalog: payload.action_catalog || [],
   196→        interaction_state: payload.interaction_state || null,
   197→      }),
   198→    });
   199→    if (!response.ok) {
   200→      throw new Error('route_failed');
   201→    }
   202→    return response.json();
   203→  }, [mode]);
   204→
   205→  if (shouldHide) return null;
   206→
   207→  const phaseTextByPhase = {
   208→    thinking: '분석 중',
   209→    tool_call: '도구 실행 중',
   210→    answering: '답변 생성 중',
   211→    stopped: '중단됨',
   212→    notice: '답변 생성 중',
   213→    error: '오류 발생',
   214→    idle: '대기 중',
   215→  };
   216→  const isActivelyWorking = isStreamingActive || isAgentRoute;
   217→  const dockStatusText = isAgentRoute
   218→    ? (phaseTextByPhase[agentStatus?.phase] || phaseTextByPhase.idle)
   219→    : '질문하세요';
   220→  const shouldShowChevron = hasActiveSession && !isAgentRoute;
   221→  const pulseActive = isRouting || isAgentControlling || isStreamingActive;
   222→  const statusDotClass = pulseActive ? 'agent-status-dot-pulse' : '';
   223→
   224→  const submitPrompt = async (prompt) => {
   225→    const normalized = String(prompt || '').trim();
   226→    if (!normalized) return;
   227→
   228→    const controlPayload = buildControlContextPayload(normalized);
   229→    setIsRouting(true);
   230→    setInlineMessage(null);
   231→
   232→    try {
   233→      const decision = await routePrompt(normalized, controlPayload);
   234→      const nextDecision = decision?.decision;
   235→
   236→      if (nextDecision === 'inline_action') {
   237→        const matchedAction = orchestratorActionCatalog.find((item) => item.id === decision?.action_id);
   238→        if (!matchedAction) {
   239→          setInlineMessage({
   240→            text: '실행 가능한 액션을 찾지 못했어요.',
   241→            canvasPrompt: normalized,
   242→          });
   243→        } else {
   244→          await executeAction(matchedAction, {
   245→            contextPayload: controlPayload,
   246→            prompt: normalized,
   247→          });
   248→        }
   249→      } else if (nextDecision === 'open_canvas') {
   250→        submitPromptToCanvas(decision?.canvas_prompt || normalized);
   251→      } else {
   252→        setInlineMessage({
   253→          text: decision?.inline_text || '자세히 보려면 캔버스를 열어주세요.',
   254→          canvasPrompt: decision?.canvas_prompt || normalized,
   255→        });
   256→      }
   257→    } catch {
   258→      setInlineMessage({
   259→        text: '자세한 분석은 캔버스에서 확인할 수 있어요.',
   260→        canvasPrompt: normalized,
   261→      });
   262→    } finally {
   263→      setIsRouting(false);
   264→    }
   265→
   266→    setInput('');
   267→  };
   268→
   269→  const handleSubmit = async (event) => {
   270→    event.preventDefault();
   271→    await submitPrompt(input || suggestedPrompt);
   272→  };
   273→
   274→  const handleResumeChat = () => {
   275→    navigate('/agent', {
   276→      state: {
   277→        mode,
   278→        contextPayload: buildControlContextPayload(''),
   279→        useWebSearch: searchEnabled,
   280→      },
   281→    });
   282→  };
   283→
   284→  // 스크롤 다운 시 AgentDock을 화면 밖으로 슬라이드
   285→  // hideBottomNav: 키보드 열림 → 본인 높이+여백만큼 아래로
   286→  // 일반: BottomNav도 함께 사라지므로 본인 높이+navH+여백만큼 아래로
   287→  const dockTranslateY = scrolledDown
   288→    ? (hideBottomNav ? 'calc(100% + 8px)' : 'calc(100% + var(--bottom-nav-h,68px) + 8px)')
   289→    : 0;
   290→
   291→  return (
   292→    <motion.div
   293→      animate={{ y: dockTranslateY }}
   294→      transition={{ type: 'spring', damping: 30, stiffness: 300 }}
   295→      className="pointer-events-none fixed left-0 right-0 z-30 flex justify-center px-4 pb-2"
   296→      style={{ bottom: `calc(${hideBottomNav ? '0px' : 'var(--bottom-nav-h,68px)'} + var(--keyboard-offset,0px))` }}
   297→    >
   298→      <div className="w-full max-w-mobile space-y-1.5">
   299→        {/* 인라인 메시지 (트레이 대체 — 필요할 때만 노출) */}
   300→        {inlineMessage?.text && (
   301→          <div className="pointer-events-auto flex items-center justify-between gap-2 rounded-[14px] border border-[var(--agent-border,#E8EBED)] bg-white px-3 py-2 shadow-[var(--agent-shadow)]">
   302→            <p className="min-w-0 truncate text-[12px] text-[#6B7684]">{inlineMessage.text}</p>
   303→            {inlineMessage.canvasPrompt && (
   304→              <button
   305→                type="button"
   306→                onClick={() => {
   307→                  submitPromptToCanvas(inlineMessage.canvasPrompt);
   308→                  setInlineMessage(null);
   309→                }}
   310→                className="flex-shrink-0 text-[12px] font-semibold text-[#FF6B00] active:opacity-70"
   311→              >
   312→                자세히
   313→              </button>
   314→            )}
   315→          </div>
   316→        )}
   317→
   318→        {/* 볼드 입력바 */}
   319→        <AgentControlPulse active={pulseActive}>
   320→          <div className="pointer-events-auto relative rounded-[20px] bg-white shadow-[0_18px_34px_rgba(255,107,0,0.34)]">
   321→            {/* 상단 상태 라인 (항상 노출) */}
   322→            <div className="flex items-center gap-2 border-b border-[#F2F4F6] px-3 py-1.5">
   323→              <button
   324→                type="button"
   325→                onClick={hasActiveSession ? handleResumeChat : undefined}
   326→                className={`flex min-w-0 flex-1 items-center gap-2 text-left ${hasActiveSession ? 'active:bg-[#F7F8FA]' : ''}`}
   327→              >
   328→                <span className={`h-1.5 w-1.5 rounded-full ${isActivelyWorking ? 'bg-[#FF6B00]' : 'bg-[#16A34A]'} ${statusDotClass}`} />
   329→                <div className="min-w-0">
   330→                  <p className={`truncate text-[12px] font-medium ${isActivelyWorking ? 'text-[#4E5968]' : 'text-[#166534]'}`}>
   331→                    {dockStatusText}
   332→                  </p>
   333→                </div>
   334→                {shouldShowChevron && (
   335→                  <svg className="ml-auto text-[#B0B8C1]" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
   336→                    <path d="m9 18 6-6-6-6" />
   337→                  </svg>
   338→                )}
   339→              </button>
   340→
   341→              <div className="ml-auto flex items-center gap-1">
   342→                <button
   343→                  type="button"
   344→                  onClick={() => setSearchEnabled((prev) => !prev)}
   345→                  className={`flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-full transition-colors ${
   346→                    searchEnabled
   347→                      ? 'bg-[#FFF2E8] text-[#FF6B00]'
   348→                      : 'bg-[#F2F4F6] text-[#8B95A1]'
   349→                  }`}
   350→                  aria-label={searchEnabled ? '인터넷 검색 켜짐' : '인터넷 검색 꺼짐'}
   351→                  title={searchEnabled ? '인터넷 검색: 켜짐' : '인터넷 검색: 꺼짐'}
   352→                >
   353→                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.9" strokeLinecap="round" strokeLinejoin="round">
   354→                    <circle cx="12" cy="12" r="9" />
   355→                    <path d="M3 12h18" />
   356→                    <path d="M12 3a15 15 0 0 1 0 18" />
   357→                    <path d="M12 3a15 15 0 0 0 0 18" />
   358→                  </svg>
   359→                </button>
   360→
   361→                <button
   362→                  type="button"
   363→                  onClick={() => navigate('/agent/history', { state: { mode, contextPayload: buildControlContextPayload('') } })}
   364→                  className="flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-full bg-[#F2F4F6] text-[#6B7684] transition-colors active:bg-[#E8EBED]"
   365→                  aria-label="대화 기록 보기"
   366→                  title="대화 기록 보기"
   367→                >
   368→                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.9" strokeLinecap="round" strokeLinejoin="round">
   369→                    <path d="M12 8v5l3 2" />
   370→                    <circle cx="12" cy="12" r="9" />
   371→                  </svg>
   372→                </button>
   373→              </div>
   374→            </div>
   375→
   376→            {showSlashMenu && (
   377→              <SlashCommandMenu
   378→                query={slashQuery}
   379→                onSelect={handleSlashCommand}
   380→                onClose={() => { setShowSlashMenu(false); setSlashQuery(''); }}
   381→                visible={showSlashMenu}
   382→              />
   383→            )}
   384→
   385→            <form
   386→              onSubmit={handleSubmit}
   387→              className="flex h-12 items-center gap-2.5 px-3"
   388→            >
   389→              <button
   390→                type="button"
   391→                onClick={() => submitPrompt(suggestedPrompt)}
   392→                className="flex h-7 w-7 flex-shrink-0 items-center justify-center rounded-full bg-[#FF6B00] text-white shadow-sm active:scale-95"
   393→                aria-label="추천 질문 사용"
   394→              >
   395→                <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
   396→                  <path d="M12 3l2 5 5 2-5 2-2 5-2-5-5-2 5-2 2-5z" />
   397→                  <path d="M19 4l.7 1.6 1.6.7-1.6.7-.7 1.6-.7-1.6-1.6-.7 1.6-.7.7-1.6z" />
   398→                  <path d="M5.5 15l.7 1.6 1.6.7-1.6.7-.7 1.6-.7-1.6-1.6-.7 1.6-.7.7-1.6z" />
   399→                </svg>
   400→              </button>
   401→
   402→              <input
   403→                type="text"
