   424→                }}
   425→                placeholder={input ? placeholder : suggestedPrompt}
   426→                data-agent-dock-input
   427→                className="min-w-0 flex-1 bg-transparent text-[14px] text-[#191F28] placeholder:text-[#B0B8C1] focus:outline-none"
