                  <path d="M12 3l2 5 5 2-5 2-2 5-2-5-5-2 5-2 2-5z" />
                  <path d="M19 4l.7 1.6 1.6.7-1.6.7-.7 1.6-.7-1.6-1.6-.7 1.6-.7.7-1.6z" />
                  <path d="M5.5 15l.7 1.6 1.6.7-1.6.7-.7 1.6-.7-1.6-1.6-.7 1.6-.7.7-1.6z" />
