                placeholder={input ? placeholder : suggestedPrompt}
                data-agent-dock-input
                className="min-w-0 flex-1 bg-transparent text-[14px] text-[#191F28] placeholder:text-[#B0B8C1] focus:outline-none"
                aria-label="에이전트 질문 입력"
