    96→/**
    97→ * 레거시 HTML에서 Plotly data/layout 추출 (하위 호환용)
    98→ * Plotly.newPlot('id', data, layout) 또는 var data/layout 패턴 매칭
    99→ */
   100→function extractPlotlyDataFromHtml(html) {
   101→  try {
   102→    // 패턴 1: Plotly.newPlot('id', [...], {...})
   103→    const plotCallMatch = html.match(
   104→      /Plotly\.(?:newPlot|react)\s*\(\s*['"][^'"]*['"]\s*,\s*([\s\S]+?)\s*,\s*(\{[\s\S]+?\})\s*[,)]/
   105→    );
   106→    if (plotCallMatch) {
   107→      // eslint-disable-next-line no-new-func
   108→      const data = new Function(`return ${plotCallMatch[1]}`)();
   109→      // eslint-disable-next-line no-new-func
   110→      const layout = new Function(`return ${plotCallMatch[2]}`)();
   111→      if (Array.isArray(data)) return { data, layout: layout || {} };
   112→    }
   113→    // 패턴 2: var data = [...]; var layout = {...};
   114→    const dataMatch = html.match(/(?:var|let|const)\s+data\s*=\s*([\s\S]+?);\s*(?:var|let|const)\s+layout/);
   115→    const layoutMatch = html.match(/(?:var|let|const)\s+layout\s*=\s*([\s\S]+?);\s*(?:Plotly|<\/script)/);
   116→    if (dataMatch && layoutMatch) {
   117→      // eslint-disable-next-line no-new-func
   118→      const data = new Function(`return ${dataMatch[1].trim()}`)();
   119→      // eslint-disable-next-line no-new-func
   120→      const layout = new Function(`return ${layoutMatch[1].trim()}`)();
   121→      if (Array.isArray(data)) return { data, layout: layout || {} };
   122→    }
   123→  } catch (e) {
   124→    console.warn('Plotly HTML 파싱 실패:', e);
   125→  }
   126→  return null;
   127→}
